mapper.select:
SELECT

FROM repair_requests rr
LEFT JOIN work_orders wo ON wo.repair_request_id = rr.id
WHERE rr.submitted_at >= #{startDate}
  AND rr.dorm_area_snapshot = #{dormArea}
  AND rr.building_no_snapshot = #{buildingNo}
ORDER BY rr.submitted_at DESC, rr.id DESC
LIMIT #{limit}

SELECT

FROM repair_requests rr
LEFT JOIN work_orders wo ON wo.repair_request_id = rr.id
WHERE rr.submitted_at >= #{startDate}
  AND rr.fault_category = #{faultCategory}
ORDER BY rr.submitted_at DESC, rr.id DESC
LIMIT #{limit}
